#!/usr/bin/env bash
# GENERATED by `ggen sync` from packs/ggen-verify-pack
# (produce_receipts_check_sh.tmpl). Receipts-class producer: schema-validates
# .ggen-v2/receipt-log.jsonl, replays the chain's hash linkage (each record's
# prev_chain_hash_hex must equal its predecessor's chain_hash_hex, genesis
# all-zeros), and re-derives the head judgment (last record's chain_hash_hex
# must equal .ggen-v2/receipt.json's). Emits ver:ReceiptsCheck with the REAL
# exit code + the replayed chain head hash. Always exits 0 itself; judgment
# happens at sync (a red check lowers the gate axis by the meet law and the
# receipts class only goes Equivalent when the replayed head matches the
# verified previous head the next receipt chains from).
set -uo pipefail
cd "$(dirname "$0")/.."
mkdir -p evidence/producers

CODE=0
HEAD_HASH="absent"
if [ ! -f .ggen-v2/receipt-log.jsonl ]; then
  CODE=1
else
  RESULT="$(python3 - <<'PYEOF'
import json, sys
prev = "0" * 64
head = "absent"
required = ["chain_hash_hex", "prev_chain_hash_hex", "payload_hash_hex", "schema"]
try:
    with open(".ggen-v2/receipt-log.jsonl") as fh:
        for lineno, line in enumerate(fh, 1):
            if not line.strip():
                continue
            rec = json.loads(line)["record"]
            for key in required:
                if key not in rec or not rec[key]:
                    raise ValueError(f"line {lineno}: missing {key}")
            if rec["prev_chain_hash_hex"] != prev:
                raise ValueError(f"line {lineno}: chain linkage broken")
            prev = rec["chain_hash_hex"]
            head = prev
    with open(".ggen-v2/receipt.json") as fh:
        if json.load(fh)["record"]["chain_hash_hex"] != head:
            raise ValueError("head receipt does not match log tail")
except Exception as exc:
    print(f"1 {head} {exc}")
    sys.exit(0)
print(f"0 {head} ok")
PYEOF
)"
  CODE="$(echo "$RESULT" | cut -d' ' -f1)"
  HEAD_HASH="$(echo "$RESULT" | cut -d' ' -f2)"
fi

OUT=evidence/producers/receipts-check.ttl
{
  echo "# GENERATED by scripts/produce-receipts-check.sh -- do not edit."
  echo "@prefix ver: <http://seanchatmangpt.github.io/packs/ggen-verify#> ."
  echo
  echo "ver:receipts-check a ver:ReceiptsCheck ;"
  echo "    ver:exitCode $CODE ;"
  echo "    ver:chainHead \"$HEAD_HASH\" ."
} > "$OUT"
echo "produce-receipts-check.sh: exit $CODE, head $HEAD_HASH -> $OUT"
exit 0

